   281→
   282→// braceIndices returns the first level curly brace indices from a string.
   283→// It returns an error in case of unbalanced braces.
   284→func braceIndices(s string) ([]int, error) {
   285→	var level, idx int
   286→	var idxs []int
   287→	for i := 0; i < len(s); i++ {
   288→		switch s[i] {
   289→		case '{':
   290→			if level++; level == 1 {
   291→				idx = i
   292→			}
   293→		case '}':
   294→			if level--; level == 0 {
   295→				idxs = append(idxs, idx, i+1)
   296→			} else if level < 0 {
   297→				return nil, fmt.Errorf("mux: unbalanced braces in %q", s)
   298→			}
   299→		}
   300→	}
   301→	if level != 0 {
   302→		return nil, fmt.Errorf("mux: unbalanced braces in %q", s)
   303→	}
   304→	return idxs, nil
   305→}
   306→
   307→// varGroupName builds a capturing group name for the indexed variable.
   308→func varGroupName(idx int) string {
   309→	return "v" + strconv.Itoa(idx)
   310→}
   311→
   312→// ----------------------------------------------------------------------------
   313→// routeRegexpGroup
   314→// ----------------------------------------------------------------------------
   315→
   316→// routeRegexpGroup groups the route matchers that carry variables.
   317→type routeRegexpGroup struct {
   318→	host    *routeRegexp
   319→	path    *routeRegexp
   320→	queries []*routeRegexp
   321→}
   322→
   323→// setMatch extracts the variables from the URL once a route matches.
   324→func (v routeRegexpGroup) setMatch(req *http.Request, m *RouteMatch, r *Route) {
   325→	// Store host variables.
   326→	if v.host != nil {
   327→		host := getHost(req)
   328→		matches := v.host.regexp.FindStringSubmatchIndex(host)
   329→		if len(matches) > 0 {
   330→			extractVars(host, matches, v.host.varsN, m.Vars)
   331→		}
   332→	}
   333→	path := req.URL.Path
   334→	if r.useEncodedPath {
   335→		path = req.URL.EscapedPath()
   336→	}
   337→	// Store path variables.
   338→	if v.path != nil {
   339→		matches := v.path.regexp.FindStringSubmatchIndex(path)
   340→		if len(matches) > 0 {
   341→			extractVars(path, matches, v.path.varsN, m.Vars)
   342→			// Check if we should redirect.
   343→			if v.path.options.strictSlash {
   344→				p1 := strings.HasSuffix(path, "/")
   345→				p2 := strings.HasSuffix(v.path.template, "/")
   346→				if p1 != p2 {
   347→					u, _ := url.Parse(req.URL.String())
   348→					if p1 {
   349→						u.Path = u.Path[:len(u.Path)-1]
   350→					} else {
   351→						u.Path += "/"
   352→					}
   353→					m.Handler = http.RedirectHandler(u.String(), http.StatusMovedPermanently)
   354→				}
   355→			}
   356→		}
   357→	}
   358→	// Store query string variables.
   359→	for _, q := range v.queries {
   360→		queryURL := q.getURLQuery(req)
   361→		matches := q.regexp.FindStringSubmatchIndex(queryURL)
   362→		if len(matches) > 0 {
   363→			extractVars(queryURL, matches, q.varsN, m.Vars)
   364→		}
   365→	}
   366→}
   367→
   368→// getHost tries its best to return the request host.
   369→// According to section 14.23 of RFC 2616 the Host header
   370→// can include the port number if the default value of 80 is not used.
   371→func getHost(r *http.Request) string {
   372→	if r.URL.IsAbs() {
   373→		return r.URL.Host
   374→	}
   375→	return r.Host
   376→}
   377→
   378→func extractVars(input string, matches []int, names []string, output map[string]string) {
   379→	for i, name := range names {
   380→		output[name] = input[matches[2*i+2]:matches[2*i+3]]
   381→	}
   382→}
