package mux

import (
	"fmt"
	"net/http"
)

func ExampleWildcardHostPortIssue() {
	// Issue #1526: host matching with wildcard routes when port is in request but not in template
	r := NewRouter()

	// Register two routes like in the issue - one without port, one with
	handler1 := func(w http.ResponseWriter, r *http.Request) {
		fmt.Fprint(w, "Handler1 (with explicit port in template)")
	}
	handler2 := func(w http.ResponseWriter, r *http.Request) {
		fmt.Fprint(w, "Handler2 (without port in template)")
	}

	r.Host("{subdomain:.+}.localhost").Subrouter().Path("/").HandlerFunc(handler2)
	r.Host("{subdomain:.+}.localhost:{port:.*}").Subrouter().Path("/").HandlerFunc(handler1)

	// Test 1: Request with port should match the first route (without port spec)
	// and extract the subdomain variable
	req1, _ := http.NewRequest("GET", "/", nil)
	req1.Host = "test.localhost:8080"

	var match1 RouteMatch
	if r.Match(req1, &match1) {
		fmt.Printf("Test 1 - Request: %s\n", req1.Host)
		fmt.Printf("  Matched handler: %v\n", match1.Handler)
		fmt.Printf("  Extracted vars: %v\n", match1.Vars)
		if subdomain, ok := match1.Vars["subdomain"]; ok && subdomain == "test" {
			fmt.Println("  ✓ subdomain correctly extracted as 'test'")
		} else {
			fmt.Println("  ✗ subdomain not extracted correctly")
		}
	}

	// Test 2: Request without port should match and extract subdomain
	req2, _ := http.NewRequest("GET", "/", nil)
	req2.Host = "test.localhost"

	var match2 RouteMatch
	if r.Match(req2, &match2) {
		fmt.Printf("\nTest 2 - Request: %s\n", req2.Host)
		fmt.Printf("  Matched handler: %v\n", match2.Handler)
