// setMatch extracts the variables from the URL once a route matches.
func (v routeRegexpGroup) setMatch(req *http.Request, m *RouteMatch, r *Route) {
	// Store host variables.
	if v.host != nil {
		host := getHost(req)
		if v.host.wildcardHostPort {
			// Don't be strict on the port match - strip port if present
			if i := strings.Index(host, ":"); i != -1 {
				host = host[:i]
			}
		}
		matches := v.host.regexp.FindStringSubmatchIndex(host)
		if len(matches) > 0 {
			extractVars(host, matches, v.host.varsN, m.Vars)
		}
	}
	path := req.URL.Path
	if r.useEncodedPath {
		path = req.URL.EscapedPath()
	}

func TestWildcardHostMatchWithPortInRequest(t *testing.T) {
	// Test case from issue #1526: route without port should extract variables correctly
	// even when the request includes a port number
	tests := []routeTest{
		{
			title:        "Host route without port, request with port in header, should extract variables",
			route:        new(Route).Host("{subdomain:.+}.localhost"),
			request:      newRequestHost("GET", "/", "test.localhost:8080"),
			vars:         map[string]string{"subdomain": "test"},
			host:         "test.localhost",
			shouldMatch:  true,
		},
		{
			title:        "Host route without port, request without port in header, should extract variables",
			route:        new(Route).Host("{subdomain:.+}.localhost"),
			request:      newRequestHost("GET", "/", "test.localhost"),
			vars:         map[string]string{"subdomain": "test"},
			host:         "test.localhost",
			shouldMatch:  true,
		},
		{
			title:        "Host route with port, request with port, should extract both variables",
			route:        new(Route).Host("{subdomain:.+}.localhost:{port:.*}"),
			request:      newRequestHost("GET", "/", "test.localhost:9090"),
			vars:         map[string]string{"subdomain": "test", "port": "9090"},
			host:         "test.localhost:9090",
			shouldMatch:  true,
		},
	}
	for _, test := range tests {
		t.Run(test.title, func(t *testing.T) {
			testRoute(t, test)
		})
	}
}

